mapper.select:
SELECT e.id, e.title, e.start_time, e.end_time, e.duration, CASE WHEN e.start_time > NOW() THEN 0 WHEN es.submit_time IS NOT NULL THEN 2 WHEN e.end_time IS NOT NULL AND e.end_time <= NOW() THEN 3 ELSE 1 END AS status FROM exam e INNER JOIN exam_class ec ON ec.exam_id = e.id AND ec.course_class_id IN
#{cid}
LEFT JOIN exam_submission es ON es.exam_id = e.id AND es.student_id = #{studentId} WHERE e.is_deleted = 0 AND e.status = 1 AND e.course_id = #{courseId} ORDER BY e.start_time DESC
